const fleet = $input.first().json;
const machines = fleet.machines || [];
const critical = machines.filter(m => m.risk_level === 'critical');
const warning = machines.filter(m => m.risk_level === 'warning');

return [{
  json: {
    has_critical: critical.length > 0,
    has_warning: warning.length > 0,
    critical_machines: critical,
    warning_machines: warning,
    fleet_summary: fleet.fleet_summary,
    all_machines: machines,
    voice_agent_trigger: critical.length > 0,
    checked_at: new Date().toISOString()
  }
}];

const data = $input.first().json;
const machine = data.critical_machines[0];

const workOrder = {
  work_order_id: `WO-${new Date().toISOString().slice(0, 10).replace(/-/g, '')}-${machine.engine_id.toString().padStart(3, '0')}`,
  machine_id: machine.engine_id,
  priority: 'CRITICAL',
  issue: `Predicted failure within ${machine.rul_hours}h`,
  failure_probability: `${machine.failure_probability}%`,
  anomaly_detected: machine.anomaly_detected,
  estimated_downtime_cost: `EUR ${(machine.rul_hours * 87).toFixed(0)}`,
  actions: [
    'Stop machine if vibration exceeds 6mm/s',
    'Inspect bearing assembly immediately',
    'Check lubrication and top up if below minimum',
    'Measure spindle runout and replace if wear exceeds tolerance',
    'Document findings and sign off the work order'
  ],
  created_at: new Date().toISOString(),
  agent: 'Factory Copilot AI'
};

return [{ json: { work_order: workOrder, machine: machine, voice_agent_trigger: true } }];

const data = $input.first().json;
const summary = data.fleet_summary;
const machines = [...data.all_machines];

const report = {
  report_type: 'fleet_health_check',
  timestamp: new Date().toISOString(),
  summary: {
    total: summary.total_machines,
    healthy: summary.healthy,
    warning: summary.warning,
    critical: summary.critical,
    avg_health: summary.avg_health
  },
  top_risks: machines
    .sort((a, b) => a.rul_hours - b.rul_hours)
    .slice(0, 3)
    .map(m => ({
      machine_id: m.engine_id,
      rul_hours: m.rul_hours,
      risk: m.risk_level,
      recommendation: m.recommendation
    })),
  voice_agent_trigger: data.voice_agent_trigger,
  next_check: new Date(Date.now() + 5 * 60 * 1000).toISOString()
};

return [{ json: report }];

const alerts = $input.all(0).map(item => item.json);
const reports = $input.all(1).map(item => item.json);

return [{
  json: {
    status: 'ok',
    checked_at: new Date().toISOString(),
    generated_alerts: alerts.length,
    alerts,
    reports
  }
}];
